{
  "grammar": [
    {
      "pattern": "Subject + 要 + Object + 嗎？",
      "structure": ["Subject", "要", "Object", "嗎"],
      "explanation_en": "Use '要' to ask if someone wants something, especially when ordering food or drinks.",
      "title": "Asking 'Do you want...?' with 要",
      "meaning": "Asking if someone wants something",
      "when_to_use": ["When offering food or drinks to someone", "When taking an order at a restaurant or shop"],
      "when_not_to_use": ["When asking about future plans (use 打算 instead)", "When asking about ability (use 會 instead)"],
      "pragmatic_notes": "In Taiwan, '你要...嗎？' is very common in casual ordering. For more polite requests, use '你要不要...？' or '請問你要...嗎？'",
      "word_order_notes": "Subject comes first, then 要, then the object, then 嗎 at the end.",
      "english_contrast": "English uses 'Do you want...?' with auxiliary verb 'do', but Chinese uses 要 directly after the subject.",
      "korean_contrast": "Korean uses '원하다' or '을래요' structure, while Chinese uses 要 directly.",
      "negative_examples": [
        {
          "text": "你要嗎水？",
          "error": "Object must come after 要, not at the end."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你水要嗎？",
          "error": "Word order is wrong; 要 must come before the object."
        }
      ],
      "transformation_drills": ["Change '你要水嗎？' to '你要茶嗎？'", "Change '你要咖啡嗎？' to '你要牛奶嗎？'"],
      "production_drills": ["Ask a friend if they want 滷肉飯", "Ask a customer if they want 牛肉麵"],
      "common_error_patterns": ["Placing object before 要", "Omitting 嗎 in questions"],
      "repair_feedback": {
        "word_order": "Remember: Subject + 要 + Object + 嗎",
        "politeness": "Add 請問 at the beginning for politeness",
        "vocabulary": "Use correct food/drink vocabulary"
      }
    },
    {
      "pattern": "Subject + 要 + Object + 還是 + Object + ？",
      "structure": ["Subject", "要", "Object", "還是", "Object"],
      "explanation_en": "Use '還是' to offer a choice between two options, common in ordering.",
      "title": "Offering Choices with 還是",
      "meaning": "Asking which one someone wants",
      "when_to_use": ["When giving two options for food or drink", "When asking for a preference between two items"],
      "when_not_to_use": ["When there are more than two options (use 或者 instead)", "When the choice is obvious"],
      "pragmatic_notes": "In Taiwan, '還是' is used for questions offering choices. It is different from '或者' which is used in statements.",
      "word_order_notes": "Subject + 要 + Option A + 還是 + Option B + ？",
      "english_contrast": "English uses 'or' in questions, but Chinese uses 還是 specifically for questions.",
      "korean_contrast": "Korean uses '아니면' or '을까요' structure, while Chinese uses 還是.",
      "negative_examples": [
        {
          "text": "你要水或者茶？",
          "error": "Use 還是 for questions, not 或者."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你要水還是茶嗎？",
          "error": "Do not add 嗎 when using 還是 in a question."
        }
      ],
      "transformation_drills": ["Change '你要水還是茶？' to '你要咖啡還是牛奶？'", "Change '你要滷肉飯還是牛肉麵？' to '你要水餃還是小菜？'"],
      "production_drills": ["Ask a friend if they want 珍珠奶茶 or 紅茶", "Ask a customer if they want 內用 or 外帶"],
      "common_error_patterns": ["Using 或者 instead of 還是", "Adding 嗎 after 還是 question"],
      "repair_feedback": {
        "word_order": "Remember: Subject + 要 + Option A + 還是 + Option B",
        "politeness": "Add 請問 at the beginning for politeness",
        "vocabulary": "Use correct food/drink vocabulary"
      }
    },
    {
      "pattern": "Subject + 不要 + Object",
      "structure": ["Subject", "不要", "Object"],
      "explanation_en": "Use '不要' to say you do not want something, often used when declining an offer.",
      "title": "Saying 'I don't want' with 不要",
      "meaning": "Expressing that you do not want something",
      "when_to_use": ["When declining an offer of food or drink", "When specifying you do not want an item"],
      "when_not_to_use": ["When you do not have something (use 沒有 instead)", "When expressing dislike (use 不喜歡 instead)"],
      "pragmatic_notes": "In Taiwan, '不要' can sound direct. For politeness, add '謝謝' or '不用了' after declining.",
      "word_order_notes": "Subject + 不要 + Object. The object comes after 不要.",
      "english_contrast": "English uses 'I don't want' with auxiliary verb 'do', but Chinese uses 不要 directly.",
      "korean_contrast": "Korean uses '싫다' or '원하지 않다' structure, while Chinese uses 不要.",
      "negative_examples": [
        {
          "text": "我不要嗎水？",
          "error": "不要 is a statement, not a question; do not add 嗎."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我不要水嗎？",
          "error": "不要 is used for statements; for questions use 要...嗎."
        }
      ],
      "transformation_drills": ["Change '我不要水' to '我不要茶'", "Change '我不要咖啡' to '我不要牛奶'"],
      "production_drills": ["Tell a waiter you do not want 小菜", "Tell a friend you do not want 珍珠奶茶"],
      "common_error_patterns": ["Using 不要 in questions", "Forgetting to add 謝謝 when declining politely"],
      "repair_feedback": {
        "word_order": "Remember: Subject + 不要 + Object",
        "politeness": "Add 謝謝 or 不用了 after 不要 for politeness",
        "vocabulary": "Use correct food/drink vocabulary"
      }
    }
  ]
}
